SELECT t.course_id as courseId, t.period, t.title, i.loginID, s.submit_date as date, t.status, c_main.title as courseName, t.start_date as startDate, t.end_date as endDate FROM test_schedule t INNER JOIN student_course c ON (t.course_id = c.course_id) INNER JOIN course c_main ON (t.course_id = c_main.course_id) INNER JOIN tb_userinfo i ON (c.loginID = i.loginID) LEFT OUTER JOIN student_test_schedule s ON ( i.loginID = s.loginID AND t.course_id = s.course_id AND t.period = s.period ) WHERE i.loginID = #{loginId}
AND t.course_id = #{course}
ORDER BY t.date DESC, 1, 2, 4 LIMIT #{pageSize} OFFSET #{pageIndex}

SELECT loginId, course_id AS courseId, period, question_no AS questionNo,
       student_answer AS studentAnswer
FROM student_test_answer
WHERE loginId = #{loginId}
  AND course_id = #{courseId}
  AND period = #{period}

SELECT status
FROM test_schedule
WHERE course_id = #{courseId}
  AND period = #{period}
  AND (start_date IS NULL OR CURDATE() >= start_date)
  AND (end_date IS NULL OR CURDATE() <= end_date)
